// 1. CAPTURA DOS DADOS (COM TRAVA DE SEGURANÇA)
const inputAnterior = $json;
const html = $input.all().map(i => i.json.data || i.json.body || "").join(" ");

// Busca a mensagem direto do Webhook para evitar o erro de 'undefined'
const msgOriginal = $('Webhook (WhatsApp)1').first().json.body.payload.body || "";
const pularBusca = inputAnterior.pular_busca_precos || false;

// 2. SE FOR APENAS CONVERSA, PARA AQUI (ECONOMIA DE TOKENS)
if (pularBusca) {
    return {
        json: {
            contexto_site: "Nenhum preço necessário.",
            input_atual: msgOriginal,
            link_loja: inputAnterior.url_cliente || "https://YOUR_STORE_URL",
            chat_history: $('BUSCAR HISTÓRICO1').all().slice(-5).map(item => (item.json.fromMe ? 'BOT: ' : 'CLIENTE: ') + item.json.body).join('\n')
        }
    };
}

// 3. LIMPEZA DO HTML
let textoLimpo = html
    .replace(/<style[\s\S]*?<\/style>/gi, "") 
    .replace(/<script[\s\S]*?<\/script>/gi, "") 
    .replace(/(<\/div>|<\/li>|<\/p>|<br>|<\/h[1-6]>|<\/span>|<\/a>)/gi, "\n")
    .replace(/<[^>]+>/g, " ") 
    .replace(/[ \t]+/g, " ") 
    .trim();

let linhas = textoLimpo.split("\n").map(l => l.trim()).filter(l => l.length > 0);
let produtosMontados = [];

for (let i = 0; i < linhas.length; i++) {
    if (linhas[i].match(/R\$\s*[\d,.]+/)) {
        let preco = linhas[i];
        let nomeProduto = "";
        for (let j = i + 1; j <= i + 3 && j < linhas.length; j++) {
            if (!linhas[j].match(/R\$\s*/) && !linhas[j].match(/%|OFF|ECONOMIZE/i) && linhas[j].length > 3) {
                nomeProduto = linhas[j];
                break;
            }
        }
        if (nomeProduto) {
            produtosMontados.push(`[PRODUTO]: ${nomeProduto} | [VALOR]: ${preco}`);
        }
    }
}

// 4. FILTRO DE RELEVÂNCIA (O QUE REALMENTE ECONOMIZA TOKENS)
const buscaTermo = msgOriginal.toLowerCase();
const palavrasChave = buscaTermo.split(' ').filter(p => p.length > 3);

const filtrados = produtosMontados.filter(p => 
    palavrasChave.some(palavra => p.toLowerCase().includes(palavra))
);

// Se achou o que o cliente queria, manda os 5 primeiros. Se não, manda 3 ofertas gerais.
const contextoFinal = filtrados.length > 0 ? filtrados.slice(0, 5) : produtosMontados.slice(0, 3);

return {
    json: {
        contexto_site: contextoFinal.join('\n'),
        input_atual: msgOriginal,
        link_loja: inputAnterior.url_cliente || "https://YOUR_STORE_URL",
        // LIMITADOR DE HISTÓRICO (Corte de 5 mensagens para economizar)
        chat_history: $('BUSCAR HISTÓRICO1').all().slice(-5).map(item => (item.json.fromMe ? 'BOT: ' : 'CLIENTE: ') + item.json.body).join('\n')
    }
};

