// 1. CAPTURA A RESPOSTA DA IA
const item = $input.first().json;
const respostaIA = item.content?.[0]?.text || item.message?.content || "";

// 2. CONVERTE O TEXTO EM OBJETO
let decisao;
try {
    const jsonLimpo = respostaIA.replace(/```json|```/g, '').trim();
    decisao = JSON.parse(jsonLimpo);
} catch (e) {
    decisao = { categoria: "OUTROS", termo_busca: "" };
}

const categoriaIA = decisao.categoria || "OUTROS";
const termo = (decisao.termo_busca || "").trim().toLowerCase();

// 3. MAPA DE URLs POR SETOR
const mapaUrls = {
    "ACOGUE": "https://YOUR_STORE_URL/loja-01/acougue-14",
    "BEBIDAS": "https://YOUR_STORE_URL/loja-01/bebidas-6",
    "KITS": "https://YOUR_STORE_URL/loja-01/kits-100",
    "PADARIA": "https://YOUR_STORE_URL/loja-01/padaria-13",
    "HORTI": "https://YOUR_STORE_URL/loja-01/hortifruti-10",
    "PERECIVEIS": "https://YOUR_STORE_URL/loja-01/frios-e-laticinios-4",
    "LIMPEZA": "https://YOUR_STORE_URL/loja-01/higiene-e-limpeza-8",
    "OFERTAS": "https://YOUR_STORE_URL/loja-01/ofertas-clube"
};

const regrasDeOuro = [
    { gatilhos: ["kit", "kiti", "combo", "cestas", "festa", "quite", "quit"], setor: "KITS" },
    { gatilhos: ["carne", "costela", "picanha", "kg", "churrasco", "bovina", "suina", "acem", "linguica", "moida"], setor: "ACOGUE" },
    { gatilhos: ["bebida", "cerveja", "refri", "suco", "agua", "coca"], setor: "BEBIDAS" },
    { gatilhos: ["pao", "padaria", "bolo", "salgado", "tortas"], setor: "PADARIA" },
    { gatilhos: ["fruta", "verdura", "legume", "horti", "batata", "tomate", "cebola"], setor: "HORTI" },
    { gatilhos: ["leite", "queijo", "manteiga", "iogurte", "frios"], setor: "PERECIVEIS" }
];

const gatilhosBloqueio = ["cpf", "rg", "pis", "carteira", "emprego", "vaga", "curriculo"];

let urlFinal = "";
let modo = "BUSCA_ESPECIFICA";
let setoresEncontrados = new Set();
let bloqueioRH = false;

// Checagem de RH/Vagas
if (gatilhosBloqueio.some(g => termo.includes(g))) {
    bloqueioRH = true;
}

if (!bloqueioRH) {
    for (const regra of regrasDeOuro) {
        if (regra.gatilhos.some(g => termo.includes(g))) {
            setoresEncontrados.add(regra.setor);
        }
    }
}

const categoriasSemBusca = ["RECLAMACAO", "INSTA", "DUVIDA_GERAL", "INSTITUCIONAL", "OUTROS"];

// Lógica de Direcionamento
if (bloqueioRH || (categoriasSemBusca.includes(categoriaIA) && termo === "" && setoresEncontrados.size === 0)) {
    modo = "APENAS_CONVERSA";
    urlFinal = "https://YOUR_STORE_URL"; 
} 
else if (setoresEncontrados.size > 1) {
    modo = "PEDIDO_COMPLEXO";
    urlFinal = "https://YOUR_STORE_URL";
}
else if (setoresEncontrados.size === 1) {
    const setorUnico = [...setoresEncontrados][0];
    urlFinal = mapaUrls[setorUnico];
    modo = "VITRINE_SETOR";
}
else if (mapaUrls[categoriaIA]) {
    if (termo.length > 3) {
        urlFinal = `https://YOUR_STORE_URL/loja-01/busca?q=${encodeURIComponent(termo)}`;
    } else {
        urlFinal = mapaUrls[categoriaIA];
        modo = "VITRINE_SETOR";
    }
} else {
    urlFinal = `https://YOUR_STORE_URL/loja-01/busca?q=${encodeURIComponent(termo)}`;
}

// RETORNO OTIMIZADO
return { 
    url_escolhida: urlFinal, 
    url_cliente: urlFinal,       
    termo_buscado: termo,
    input_atual: $('Webhook (WhatsApp)1').first().json.body.payload.body, 
    categoria_ia: setoresEncontrados.size > 0 ? "MIX_PRODUTOS" : categoriaIA,
    modo_operacao: modo,
    // Se for apenas conversa, você pode usar esse campo em um nó IF 
    // adiante para pular a raspagem de preços e economizar tokens.
    pular_busca_precos: (modo === "APENAS_CONVERSA" || bloqueioRH) ? true : false
};

